const query = $input.item.json.query || {};
let formulas = [];
if (query.month && query.year) {
    formulas.push(`DATETIME_FORMAT({Created_Time}, 'YYYY-MM') = '${query.year}-${query.month}'`);
}
if (query.status) {
    formulas.push(`{Process_Status} = '${query.status}'`);
}
if (query.batch) {
    formulas.push(`{Batch_Number} = '${query.batch}'`);
}
if (query.search) {
    formulas.push(`OR(FIND('${query.search}', {Customer_Name}), FIND('${query.search}', {Order_ID}))`);
}

let finalFormula = "";
if (formulas.length > 0) {
    finalFormula = `AND(${formulas.join(', ')})`;
}

return { json: { formula: finalFormula } };

const items = $input.all();
if (items.length === 0 || !items[0].json.id) return { json: { success: true, count: 0, orders: [] } };

const mainOrders = items.map(item => {
    const fields = item.json.fields || {};
    return {
        id: item.json.id,
        Order_ID: fields.Order_ID,
        Date: item.json.createdTime,
        Customer: fields.Customer_Name,
        Batch: fields.Batch_Number || '',
        Status: fields.Process_Status || '0 什麼都未做',
        Admin_Notes: fields.Admin_Notes || '',
        Sales: fields.Final_Sale_Price || 0,
        Cost: fields.Total_Cost || 0,
        Net_Profit: fields.Net_Profit || 0,
        Order_Items_Links: fields.Order_Items || []
    };
});
return { json: { mainOrders } };

const mainOrders = $input.item.json.mainOrders || [];
let allSubItemIds = [];
mainOrders.forEach(mo => {
    if (mo.Order_Items_Links && mo.Order_Items_Links.length > 0) {
        allSubItemIds = allSubItemIds.concat(mo.Order_Items_Links);
    }
});

if (allSubItemIds.length === 0) {
    return { json: { formula: "" } };
}

// We batch them if > 100, but usually for one view it's < 100 items.
const uniqueIds = [...new Set(allSubItemIds)];
const formulaParts = uniqueIds.map(id => `RECORD_ID()='${id}'`);
let chunks = [];
for (let i = 0; i < formulaParts.length; i+=50) {
   chunks.push(`OR(${formulaParts.slice(i, i+50).join(',')})`);
}
let finalFormula = chunks.length > 1 ? `OR(${chunks.join(',')})` : chunks[0];
return { json: { formula: finalFormula, mainOrders } };

const subItemsData = $input.all();
const mainOrdersContext = $items("Build SubItems Formula", 0, 0)[0].json.mainOrders;

// Map subitems by ID
const subItemsMap = {};
if (subItemsData.length > 0 && subItemsData[0].json.id) {
    subItemsData.forEach(item => {
        const fields = item.json.fields || {};
        subItemsMap[item.json.id] = {
            id: item.json.id,
            Item_ID: fields.Item_ID,
            Product: fields.Product_Link ? fields.Product_Link[0] : '', // Might need name instead of ID
            Category: fields.Item_Category ? fields.Item_Category[0] : '',
            Qty: fields.Quantity || 0,
            BaseCost: fields.Item_BaseCost ? fields.Item_BaseCost[0] : 0,
            Engraving: fields.Engraving_Text || '',
            Specification: fields.Specification || ''
        };
    });
}

// Attach to main orders
mainOrdersContext.forEach(mo => {
    mo.items = [];
    mo.Order_Items_Links.forEach(linkId => {
        if (subItemsMap[linkId]) {
            mo.items.push(subItemsMap[linkId]);
        }
    });
});

return { 
  json: { 
    success: true, 
    count: mainOrdersContext.length, 
    orders: mainOrdersContext 
  }
};
